Object.keys(LANG_EXPEDITIONS).forEach(lang => {
    if (!LANG_OTHER[lang]) LANG_OTHER[lang] = {};
    Object.assign(LANG_OTHER[lang], LANG_EXPEDITIONS[lang]);
});

Object.keys(LANG_EXPEDITIONS).forEach(lang => {
    if (LANG_SHIPS[lang]) {
        ['small_cargo','large_cargo','light_fighter','heavy_fighter','cruiser','battleship','colony_ship','recycler','esp_probe','bomber','destroyer','death_star','battlecruiser','reaper','pathfinder'].forEach(shipKey => {
            const shipName = LANG_EXPEDITIONS[lang][`ship_${shipKey}`];
            if (shipName && !LANG_SHIPS[lang][shipKey]) {
                LANG_SHIPS[lang][shipKey] = shipName;
            }
        });
    }
});

const langCache = new Map();

function getLangDict(lang) {
  if (langCache.has(lang)) return langCache.get(lang);
  const buildings = LANG_BUILDINGS[lang] || LANG_BUILDINGS.ru;
  const research = LANG_RESEARCH[lang] || LANG_RESEARCH.ru;
  const lfBuildings = LANG_LF_BUILDINGS[lang] || LANG_LF_BUILDINGS.ru;
  const lfResearch = LANG_LF_RESEARCH[lang] || LANG_LF_RESEARCH.ru;
  const ships = LANG_SHIPS[lang] || LANG_SHIPS.ru;
  const other = LANG_OTHER[lang] || LANG_OTHER.ru;

  const combinedDict = {
    ...other,
    ...Object.fromEntries(buildings.map((name, idx) => [idx, name.trim()])),
    ...Object.fromEntries(research.map((name, idx) => [100 + idx, name.trim()])),
    ...Object.fromEntries(Object.entries(lfBuildings).map(([id, name]) => [`lf_b_${id}`, name.trim()])),
    ...Object.fromEntries(Object.entries(lfResearch).map(([id, name]) => [`lf_r_${id}`, name.trim()])),
    ...Object.fromEntries(Object.entries(ships).map(([id, name]) => [`ship_${id}`, name.trim()]))
  };
  langCache.set(lang, combinedDict);
  return combinedDict;
}
window.getLangDict = getLangDict;